changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nrf_impact_assessor') THEN
        GRANT INSERT, DELETE ON
            public.coefficient_layer,
            public.edp_boundary_layer,
            public.edp_edges,
            public.gcn_ponds,
            public.gcn_risk_zones,
            public.lookup_table,
            public.lpa_boundaries,
            public.nn_catchments,
            public.subcatchments,
            public.wwtw_catchments
        TO nrf_impact_assessor;
    END IF;
END $$;

rollback.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nrf_impact_assessor') THEN
        REVOKE INSERT, DELETE ON
            public.coefficient_layer,
            public.edp_boundary_layer,
            public.edp_edges,
            public.gcn_ponds,
            public.gcn_risk_zones,
            public.lookup_table,
            public.lpa_boundaries,
            public.nn_catchments,
            public.subcatchments,
            public.wwtw_catchments
        FROM nrf_impact_assessor;
    END IF;
END $$;
